// Provide deterministic analyzed content for manual testing.
return [{
  json: {
    id: 'manual:https://example.com/ai-agent',
    source: 'manual',
    title: 'AI Agent 與工作流',
    url: 'https://example.com/ai-agent',
    language: 'zh-TW',
    content: 'AI Agent 不應只負責生成文字，也應根據工具結果規劃下一步。',
    analysis: {
      topic: 'AI Agent',
      coreIdea: 'AI Agent 應根據工具結果規劃下一步',
      audience: 'n8n 與自動化使用者',
      angles: ['Agent orchestration'],
      keywords: ['AI Agent', 'n8n', 'workflow automation']
    },
    metadata: {
      status: 'analyzed'
    }
  }
}];

// Build a semantic query for retrieving relevant writing memory.
const input = $input.first().json;
const body = input.body ?? input;

if (String(body.qdrantBaseUrl).includes('YOUR-QDRANT-CLUSTER')) {
  throw new Error('SetMemoryRetrievalConfig.qdrantBaseUrl must be replaced with your Qdrant Cloud URL');
}

const topic = body.analysis?.topic ?? body.title ?? '';
const coreIdea = body.analysis?.coreIdea ?? body.content ?? '';
const audience = body.analysis?.audience ?? '';
const angles = Array.isArray(body.analysis?.angles) ? body.analysis.angles : [];
const keywords = Array.isArray(body.analysis?.keywords) ? body.analysis.keywords : [];

const queryText = [
  `Topic: ${topic}`,
  `Core idea: ${coreIdea}`,
  `Audience: ${audience}`,
  `Angles: ${angles.join(', ')}`,
  `Keywords: ${keywords.join(', ')}`
].join('\n');

return [{
  json: {
    original: body,
    queryText,
    qdrantBaseUrl: String(body.qdrantBaseUrl).replace(/\/$/, ''),
    collection: body.collection,
    embeddingModel: body.embeddingModel,
    topK: Number(body.topK),
    scoreThreshold: Number(body.scoreThreshold)
  }
}];

// Attach the query vector.
const response = $input.first().json;
const request = $('BuildMemoryQuery').first().json;
const vector = response.data?.[0]?.embedding;

if (!Array.isArray(vector) || vector.length === 0) {
  throw new Error('NVIDIA embedding response does not contain data[0].embedding');
}

return [{ json: { ...request, vector } }];

