// Merge the retrieved writing memory into the current content contract.
const response = $input.first().json;
const request = $('AttachMemoryQueryEmbedding').first().json;
const original = request.original;
const points = response.result?.points ?? response.result ?? [];

const memories = (Array.isArray(points) ? points : [])
  .map((point) => ({
    pointId: String(point.id ?? ''),
    score: Number(point.score ?? 0),
    memoryId: String(point.payload?.memory_id ?? ''),
    articleId: String(point.payload?.article_id ?? ''),
    rules: Array.isArray(point.payload?.rules) ? point.payload.rules : [],
    avoidPhrases: Array.isArray(point.payload?.avoid_phrases) ? point.payload.avoid_phrases : [],
    preferredPatterns: Array.isArray(point.payload?.preferred_patterns) ? point.payload.preferred_patterns : [],
    summary: String(point.payload?.summary ?? '')
  }))
  .slice(0, request.topK);

const mergedRules = [];
const seenRules = new Set();

for (const memory of memories) {
  for (const rule of memory.rules) {
    const text = String(rule.rule ?? '').trim();
    if (!text || seenRules.has(text)) continue;
    seenRules.add(text);
    mergedRules.push({
      category: String(rule.category ?? 'generalRules'),
      rule: text,
      confidence: Number(rule.confidence ?? 0.5),
      sourceMemoryId: memory.memoryId,
      similarityScore: memory.score
    });
  }
}

return [{
  json: {
    ...original,
    writingMemoryContext: {
      query: request.queryText,
      collection: request.collection,
      memories,
      memoryCount: memories.length,
      mergedRules: mergedRules.slice(0, 20),
      avoidPhrases: [...new Set(memories.flatMap((memory) => memory.avoidPhrases))].slice(0, 30),
      preferredPatterns: [...new Set(memories.flatMap((memory) => memory.preferredPatterns))].slice(0, 30)
    },
    metadata: {
      ...original.metadata,
      memoryRetriever: '12-style-memory-retriever',
      memoryRetrieverVersion: '1.2.0',
      status: 'memory_retrieved',
      memoryRetrievedAt: new Date().toISOString()
    }
  }
}];
